import{_ as e,o as a,c as s,ae as i}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Deduplicate Second Installs With APIs","description":"","frontmatter":{"title":"Deduplicate Second Installs With APIs","slug":"deduplicate-second-installs-with-apis"},"headers":[],"relativePath":"developer-hub/deduplicate-second-installs-with-apis.md","filePath":"developer-hub/deduplicate-second-installs-with-apis.md"}'),r={name:"developer-hub/deduplicate-second-installs-with-apis.md"};function o(n,t,l,d,p,c){return a(),s("div",null,[...t[0]||(t[0]=[i('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>iOS 14.5 brought big changes to the mobile attribution ecosystem. One big change is that IDFA is not accessible on app install, but it can be accessed later if the user consents to <a href="https://developer.apple.com/app-store/user-privacy-and-data-use/" target="_blank" rel="noreferrer">Apple&#39;s AppTrackingTransparency framework</a>. Currently, if the user installed the mobile app via a paid ad, then Branch will publish a second install event for that user that is attributed to the ad (assuming the user allowed tracking on both source and destination apps). This means that for a subset of users, there are technically two install events. In order to ensure you see accurate counts for installs, Branch has now provided functionality to &quot;remove&quot; the first unattributed install.</p><h2 id="how-does-it-work" tabindex="-1">How Does It Work? <a class="header-anchor" href="#how-does-it-work" aria-label="Permalink to &quot;How Does It Work?&quot;">​</a></h2><ol><li><p>User sees a paid ad in a publisher app (ex. Facebook/Instagram).</p></li><li><p>User clicks the ad and gets routed to App Store to download the advertiser app.</p></li><li><p>User installs and opens the advertiser app.</p></li><li><p>An unattributed (<em>first</em>) install is reported in Branch&#39;s attribution system.</p></li></ol><p>.png)</p><ol start="5"><li><p>After some time or after an event, the advertiser app prompts the user for tracking through Apple&#39;s AppTrackingTransparency framework.</p></li><li><p>If the user opts into tracking in the advertiser app <strong>and</strong> the user has opted into tracking in the publisher app where they originally saw the paid ad, then Branch will report a <em>second</em> install.</p></li><li><p>Once the deduplication is enabled, Branch will automatically &quot;remove&quot; the first unattributed install. The second install will take the timestamp of the first install.</p></li></ol><p>.png)</p><h2 id="deduplicate-installs-using-branch-apis" tabindex="-1">Deduplicate installs using Branch APIs <a class="header-anchor" href="#deduplicate-installs-using-branch-apis" aria-label="Permalink to &quot;Deduplicate installs using Branch APIs&quot;">​</a></h2><p>You can enable the deduplication of installs if you are using the following APIs:</p><ul><li><p><a href="./query-api.html">Query API</a></p></li><li><p><a href="./cohort-api.html">Cohort API</a></p></li></ul><p>You can include the <code>enable_install_recalculation</code> boolean parameter on these APIs to de-dupe installs.</p><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>Parameter</strong></td><td><code>enable_install_recalculation</code></td></tr><tr><td><strong>Description</strong></td><td>De-dupe unattributed installs caused by duplicate events from non-opted-in users coming from paid ads.</td></tr><tr><td><strong>Required Parameter</strong></td><td>No</td></tr><tr><td><strong>Parameter Location</strong></td><td>Request body</td></tr><tr><td><strong>Default Value</strong></td><td><code>false</code></td></tr><tr><td><strong>Format</strong></td><td>Boolean</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Tip</p><p>If you just want to change the views/reports that you see in Branch, follow the steps in our marketer documentation.</p></div>',13)])])}const m=e(r,[["render",o]]);export{u as __pageData,m as default};
